import React, { useState, useEffect } from 'react';
import { HandicapResult } from '../types';

const HandicapCalculator: React.FC = () => {
  const [stake, setStake] = useState<string>('');
  const [oddDraw, setOddDraw] = useState<string>('');
  const [oddWin, setOddWin] = useState<string>('');
  const [result, setResult] = useState<HandicapResult | null>(null);
  const [lastOp, setLastOp] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const calculate = (operation: string | null = lastOp) => {
    if (!operation) return;

    // Validate inputs
    if (!stake || !oddDraw || !oddWin) {
      if (operation !== lastOp) { // Only show error if user clicked a button
         setError("Preencha todos os campos corretamente.");
      }
      return;
    }

    setError(null);
    setLastOp(operation);

    const s = parseFloat(stake);
    const od = parseFloat(oddDraw);
    const ow = parseFloat(oddWin);

    if (isNaN(s) || isNaN(od) || isNaN(ow)) return;

    let finalOdd = 0;
    let stakeDraw = 0;
    let stakeWin = 0;

    switch (operation) {
      case 'dc': // Dupla Chance (+0.5)
        finalOdd = (od * ow) / (od + ow);
        stakeDraw = (s * ow) / (od + ow);
        stakeWin = s - stakeDraw;
        break;
      case 'dnb': // Empate Anula (0.0)
        stakeDraw = s / od;
        stakeWin = s - stakeDraw;
        finalOdd = (stakeWin * ow) / s;
        break;
      case 'mais025': // +0.25
        // Formula from source: let x = (100 * oddml + 100) / (2 * oddempate + oddml) / 100;
        const x = (100 * ow + 100) / (2 * od + ow) / 100;
        stakeDraw = s * x;
        stakeWin = s - stakeDraw;
        finalOdd = (stakeWin * ow) / s;
        break;
      case 'menos025': // -0.25
        stakeDraw = s / 2 / od;
        stakeWin = s - stakeDraw;
        finalOdd = (stakeWin * ow) / s;
        break;
      default:
        return;
    }

    setResult({
      finalOdd,
      stakeDraw,
      stakeWin
    });
  };

  // Re-calculate on input change if an operation was already selected
  useEffect(() => {
    if (lastOp) {
      calculate(lastOp);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [stake, oddDraw, oddWin]);

  return (
    <div className="max-w-2xl mx-auto w-full animate-in fade-in zoom-in duration-300">
      <h2 className="text-3xl font-bold text-white mb-8 text-center">Handicap Manual</h2>

      <div className="bg-slate-800 p-6 rounded-2xl shadow-xl border border-slate-700">
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">Stake (Valor da aposta)</label>
            <input
              type="number"
              value={stake}
              onChange={(e) => setStake(e.target.value)}
              placeholder="Ex: 100"
              className="w-full bg-slate-900 border border-slate-600 text-white rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">Odd do Empate</label>
              <input
                type="number"
                value={oddDraw}
                onChange={(e) => setOddDraw(e.target.value)}
                placeholder="Ex: 3.50"
                className="w-full bg-slate-900 border border-slate-600 text-white rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">Odd da Vitória</label>
              <input
                type="number"
                value={oddWin}
                onChange={(e) => setOddWin(e.target.value)}
                placeholder="Ex: 2.10"
                className="w-full bg-slate-900 border border-slate-600 text-white rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
              />
            </div>
          </div>

          {error && (
            <div className="text-red-400 text-sm text-center bg-red-900/20 p-2 rounded-lg border border-red-900/50">
              {error}
            </div>
          )}

          <div className="grid grid-cols-2 gap-3 pt-4">
            <button 
                onClick={() => calculate('menos025')}
                className={`p-3 rounded-xl font-semibold transition-all ${lastOp === 'menos025' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'bg-slate-700 text-slate-200 hover:bg-slate-600'}`}
            >
              Handicap -0.25
            </button>
            <button 
                onClick={() => calculate('dnb')}
                className={`p-3 rounded-xl font-semibold transition-all ${lastOp === 'dnb' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'bg-slate-700 text-slate-200 hover:bg-slate-600'}`}
            >
              Empate Anula (0.0)
            </button>
            <button 
                onClick={() => calculate('mais025')}
                className={`p-3 rounded-xl font-semibold transition-all ${lastOp === 'mais025' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'bg-slate-700 text-slate-200 hover:bg-slate-600'}`}
            >
              Handicap +0.25
            </button>
            <button 
                onClick={() => calculate('dc')}
                className={`p-3 rounded-xl font-semibold transition-all ${lastOp === 'dc' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'bg-slate-700 text-slate-200 hover:bg-slate-600'}`}
            >
              Dupla Chance (+0.5)
            </button>
          </div>
        </div>

        {result && (
          <div className="mt-8 bg-slate-900/50 rounded-xl p-6 border border-slate-700 animate-in slide-in-from-bottom-2">
            <h3 className="text-slate-400 text-sm font-semibold uppercase tracking-wider mb-4">Resultados</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 text-center">
              <div>
                <p className="text-slate-500 text-xs uppercase mb-1">Odd Final</p>
                <p className="text-2xl font-bold text-emerald-400">{result.finalOdd.toFixed(3)}</p>
              </div>
              <div>
                <p className="text-slate-500 text-xs uppercase mb-1">Apostar no Empate</p>
                <p className="text-2xl font-bold text-white">R$ {result.stakeDraw.toFixed(2)}</p>
              </div>
              <div>
                <p className="text-slate-500 text-xs uppercase mb-1">Apostar na Vitória</p>
                <p className="text-2xl font-bold text-white">R$ {result.stakeWin.toFixed(2)}</p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default HandicapCalculator;

import React, { useState, useEffect, useCallback } from 'react';
import { GoalsResult } from '../types';
import { Minus, Plus, ArrowUpCircle, ArrowDownCircle } from 'lucide-react';

const GoalsCalculator: React.FC = () => {
  const [isOver, setIsOver] = useState(true);
  const [goals, setGoals] = useState(0.5);
  const [stake, setStake] = useState('');
  const [oddExact, setOddExact] = useState('');
  const [oddOU, setOddOU] = useState('');
  const [result, setResult] = useState<GoalsResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Determine the "Exactly" number based on current line and market
  const getExactGoals = (line: number, over: boolean) => {
    const decimal = line % 1;
    let exact = Math.floor(line);

    if (over) {
      if (decimal === 0.5 || decimal === 0.75) {
        exact = Math.floor(line) + 1;
      }
    } else {
      if (decimal === 0.75) {
        exact = Math.floor(line) + 1;
      }
    }
    return exact;
  };

  const exactValue = getExactGoals(goals, isOver);
  const marketLabel = isOver ? "Mais" : "Menos";

  const calculate = useCallback(() => {
    if (!stake || !oddExact || !oddOU) {
        setResult(null);
        return;
    }

    const s = parseFloat(stake);
    const oExact = parseFloat(oddExact);
    const oOU = parseFloat(oddOU);

    if (isNaN(s) || isNaN(oExact) || isNaN(oOU)) return;

    // Use toFixed to avoid float precision issues (0.7500001)
    const decimalPart = parseFloat((goals % 1).toFixed(2));

    let selectedLine = '';

    if (decimalPart === 0) selectedLine = 'linha0';
    else if (decimalPart === 0.25) selectedLine = isOver ? 'over025' : 'under025';
    else if (decimalPart === 0.75) selectedLine = isOver ? 'over075' : 'under075';
    else if (decimalPart === 0.5) selectedLine = 'linha05';
    else {
      setError("Linha inválida");
      return;
    }

    let stakeExactly = 0;
    let stakeOU = 0;
    let finalOdd = 0;

    // Common factor
    const x = (100 * oOU + 100) / (2 * oExact + oOU) / 100;

    switch (selectedLine) {
      case "linha0":
        stakeExactly = s / oExact;
        stakeOU = s - stakeExactly;
        finalOdd = (stakeOU * oOU) / s;
        break;
      case "over025":
        stakeExactly = s / 2 / oExact;
        stakeOU = s - stakeExactly;
        finalOdd = (stakeOU * oOU) / s;
        break;
      case "over075":
        stakeExactly = s * x;
        stakeOU = s - stakeExactly;
        finalOdd = (stakeOU * oOU) / s;
        break;
      case "under025":
        stakeExactly = s * x;
        stakeOU = s - stakeExactly;
        finalOdd = (stakeOU * oOU) / s;
        break;
      case "under075":
        stakeExactly = s / 2 / oExact;
        stakeOU = s - stakeExactly;
        finalOdd = (stakeOU * oOU) / s;
        break;
      case "linha05":
        finalOdd = (oExact * oOU) / (oExact + oOU);
        stakeExactly = (s * oOU) / (oExact + oOU);
        stakeOU = s - stakeExactly;
        break;
      default:
        return;
    }

    setError(null);
    setResult({ finalOdd, stakeExactly, stakeOU });
  }, [goals, isOver, stake, oddExact, oddOU]);

  useEffect(() => {
    calculate();
  }, [calculate]);

  const changeGoals = (amount: number) => {
    setGoals(prev => {
        const newVal = prev + amount;
        return parseFloat(Math.max(0.5, newVal).toFixed(2));
    });
  };

  return (
    <div className="max-w-2xl mx-auto w-full animate-in fade-in zoom-in duration-300">
      <h2 className="text-3xl font-bold text-white mb-8 text-center">Calculadora de Gols</h2>

      <div className="bg-slate-800 p-6 rounded-2xl shadow-xl border border-slate-700">

        {/* Market Selector & Line Controls */}
        <div className="flex flex-col md:flex-row items-center justify-between mb-8 gap-4">
            <button 
                onClick={() => setIsOver(!isOver)}
                className={`
                    flex items-center gap-2 px-6 py-3 rounded-full font-bold text-lg transition-all w-full md:w-auto justify-center
                    ${isOver ? 'bg-emerald-500 text-white hover:bg-emerald-600' : 'bg-red-500 text-white hover:bg-red-600'}
                `}
            >
                {isOver ? <ArrowUpCircle size={24}/> : <ArrowDownCircle size={24}/>}
                <span>{isOver ? 'Over (Mais)' : 'Under (Menos)'}</span>
            </button>

            <div className="flex items-center gap-4 bg-slate-900 p-2 rounded-xl border border-slate-700">
                <button 
                    onClick={() => changeGoals(-0.25)}
                    className="p-2 hover:bg-slate-700 rounded-lg text-slate-300 transition-colors"
                >
                    <Minus size={20} />
                </button>
                <div className="text-2xl font-mono font-bold text-white w-20 text-center">
                    {goals.toFixed(2)}
                </div>
                <button 
                    onClick={() => changeGoals(0.25)}
                    className="p-2 hover:bg-slate-700 rounded-lg text-slate-300 transition-colors"
                >
                    <Plus size={20} />
                </button>
            </div>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">Stake (Valor da aposta)</label>
            <input
              type="number"
              value={stake}
              onChange={(e) => setStake(e.target.value)}
              placeholder="Ex: 100"
              className="w-full bg-slate-900 border border-slate-600 text-white rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">
                Odd "Exatamente {exactValue} gols"
              </label>
              <input
                type="number"
                value={oddExact}
                onChange={(e) => setOddExact(e.target.value)}
                placeholder="Ex: 3.50"
                className="w-full bg-slate-900 border border-slate-600 text-white rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">
                Odd "{marketLabel} de {exactValue} gols"
              </label>
              <input
                type="number"
                value={oddOU}
                onChange={(e) => setOddOU(e.target.value)}
                placeholder="Ex: 1.90"
                className="w-full bg-slate-900 border border-slate-600 text-white rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
              />
            </div>
          </div>

          {error && (
            <div className="text-red-400 text-sm text-center bg-red-900/20 p-2 rounded-lg border border-red-900/50">
              {error}
            </div>
          )}

        </div>

        {result && (
          <div className="mt-8 bg-slate-900/50 rounded-xl p-6 border border-slate-700 animate-in slide-in-from-bottom-2">
            <h3 className="text-slate-400 text-sm font-semibold uppercase tracking-wider mb-4">Resultados</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 text-center">
              <div>
                <p className="text-slate-500 text-xs uppercase mb-1">Odd Final</p>
                <p className="text-2xl font-bold text-emerald-400">{result.finalOdd.toFixed(3)}</p>
              </div>
              <div>
                <p className="text-slate-500 text-xs uppercase mb-1">Apostar "Exatamente"</p>
                <p className="text-2xl font-bold text-white">R$ {result.stakeExactly.toFixed(2)}</p>
              </div>
              <div>
                <p className="text-slate-500 text-xs uppercase mb-1">Apostar "{marketLabel}"</p>
                <p className="text-2xl font-bold text-white">R$ {result.stakeOU.toFixed(2)}</p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default GoalsCalculator;

import React, { useState, useMemo } from 'react';
import { EvOddInput } from '../types';
import { Trash2, Plus, RotateCcw } from 'lucide-react';

const EvCalculator: React.FC = () => {
  const [odds, setOdds] = useState<EvOddInput[]>([
    { id: 1, odd: '', betOdd: '' },
    { id: 2, odd: '', betOdd: '' }
  ]);

  const addOddField = () => {
    const newId = odds.length > 0 ? Math.max(...odds.map(o => o.id)) + 1 : 1;
    setOdds([...odds, { id: newId, odd: '', betOdd: '' }]);
  };

  const removeOddField = (id: number) => {
    if (odds.length <= 2) return; // Minimum 2 inputs
    setOdds(odds.filter(o => o.id !== id));
  };

  const updateOdd = (id: number, field: 'odd' | 'betOdd', value: string) => {
    setOdds(odds.map(o => o.id === id ? { ...o, [field]: value } : o));
  };

  const resetFields = () => {
    setOdds([
        { id: 1, odd: '', betOdd: '' },
        { id: 2, odd: '', betOdd: '' }
    ]);
  };

  // Calculate Fair Odds and EV
  const calculationResults = useMemo(() => {
    // 1. Calculate Sum of Inverses (for reference odds only)
    let sumInverses = 0;
    const validOddsCount = odds.filter(o => parseFloat(o.odd) > 1).length;

    odds.forEach(item => {
        const val = parseFloat(item.odd);
        if (!isNaN(val) && val > 1) {
            sumInverses += 1 / val;
        }
    });

    if (validOddsCount < 2 || sumInverses === 0) return {};

    const results: Record<number, { fairOdd: string, margin: string, marginColor: string }> = {};

    odds.forEach(item => {
        const val = parseFloat(item.odd);
        if (!isNaN(val) && val > 1) {
            // Fair Probability = (1 / Odd) / SumInverses
            const fairProb = (1 / val) / sumInverses;
            const fairOdd = 1 / fairProb;

            let marginText = "";
            let marginColor = "text-slate-500";

            const betOddVal = parseFloat(item.betOdd);
            if (!isNaN(betOddVal) && betOddVal > 0) {
                const margin = (betOddVal / fairOdd) * 100;
                marginText = `${margin.toFixed(2)}%`;

                if (margin > 100) marginColor = "text-emerald-400";
                else if (margin === 100) marginColor = "text-blue-400";
                else marginColor = "text-red-400";
            }

            results[item.id] = {
                fairOdd: fairOdd.toFixed(3),
                margin: marginText,
                marginColor
            };
        }
    });

    return results;

  }, [odds]);


  return (
    <div className="max-w-3xl mx-auto w-full animate-in fade-in zoom-in duration-300">
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-3xl font-bold text-white text-center flex-grow">Calculadora EV%</h2>
        <button 
            onClick={resetFields}
            className="text-slate-400 hover:text-white transition-colors p-2 bg-slate-800 rounded-full hover:bg-slate-700"
            title="Limpar tudo"
        >
            <RotateCcw size={18} />
        </button>
      </div>

      <div className="bg-slate-800 p-6 rounded-2xl shadow-xl border border-slate-700">
        <div className="space-y-6">

          {odds.map((item, index) => {
            const result = calculationResults[item.id];
            const hasValidOdd = parseFloat(item.odd) > 1;

            return (
                <div key={item.id} className="relative bg-slate-900/50 p-4 rounded-xl border border-slate-700 transition-all hover:border-slate-600">
                    <div className="flex flex-col md:flex-row gap-4 items-start md:items-end">

                        {/* Reference Odd Input */}
                        <div className="flex-1 w-full">
                            <label className="block text-xs font-medium text-slate-500 mb-1 uppercase tracking-wider">
                                Odd {index + 1} (Referência)
                            </label>
                            <input
                                type="number"
                                value={item.odd}
                                onChange={(e) => updateOdd(item.id, 'odd', e.target.value)}
                                placeholder="Ex: 1.90"
                                className="w-full bg-slate-800 border border-slate-600 text-white rounded-lg p-2.5 focus:ring-2 focus:ring-emerald-500 outline-none"
                            />
                        </div>

                        {/* Fair Odd Display */}
                        <div className={`flex-1 w-full md:text-center transition-opacity duration-300 ${result ? 'opacity-100' : 'opacity-0'}`}>
                             <label className="block text-xs font-medium text-slate-500 mb-1 uppercase tracking-wider">Fair Odd</label>
                             <div className="text-xl font-mono font-bold text-white py-2">
                                {result ? result.fairOdd : '-'}
                             </div>
                        </div>

                         {/* Betting Odd Input */}
                        <div className={`flex-1 w-full transition-opacity duration-300 ${hasValidOdd ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                            <label className="block text-xs font-medium text-slate-500 mb-1 uppercase tracking-wider">
                                Odd Apostada
                            </label>
                            <input
                                type="number"
                                value={item.betOdd}
                                onChange={(e) => updateOdd(item.id, 'betOdd', e.target.value)}
                                placeholder="Sua odd"
                                className="w-full bg-slate-800 border border-slate-600 text-white rounded-lg p-2.5 focus:ring-2 focus:ring-purple-500 outline-none"
                            />
                        </div>

                         {/* Margin Display */}
                         <div className={`flex-1 w-full md:text-center transition-opacity duration-300 ${result && result.margin ? 'opacity-100' : 'opacity-0'}`}>
                             <label className="block text-xs font-medium text-slate-500 mb-1 uppercase tracking-wider">EV (Margem)</label>
                             <div className={`text-xl font-mono font-bold py-2 ${result?.marginColor}`}>
                                {result ? result.margin : '-'}
                             </div>
                        </div>

                        {/* Delete Button */}
                        {odds.length > 2 && (
                            <button 
                                onClick={() => removeOddField(item.id)}
                                className="absolute top-2 right-2 md:static md:mb-3 text-slate-600 hover:text-red-400 transition-colors"
                            >
                                <Trash2 size={18} />
                            </button>
                        )}
                    </div>
                </div>
            );
          })}

          <button
            onClick={addOddField}
            className="w-full py-3 border-2 border-dashed border-slate-700 text-slate-500 rounded-xl hover:border-emerald-500 hover:text-emerald-500 transition-all flex items-center justify-center gap-2 font-medium"
          >
            <Plus size={20} />
            Adicionar Odd
          </button>
        </div>
      </div>
    </div>
  );
};

