import React, { useState, useEffect } from 'react';

const SurebetCalculator: React.FC = () => {
  const [totalStake, setTotalStake] = useState('100');
  const [odds, setOdds] = useState<{id: number, val: string}[]>([
      { id: 1, val: '' }, { id: 2, val: '' }
  ]);
  const [is3Way, setIs3Way] = useState(false);

  useEffect(() => {
    // Adjust inputs based on 2-way or 3-way
    if (is3Way && odds.length === 2) {
        setOdds([...odds, { id: 3, val: '' }]);
    } else if (!is3Way && odds.length === 3) {
        setOdds(odds.slice(0, 2));
    }
  }, [is3Way]);

  const updateOdd = (idx: number, val: string) => {
    const newOdds = [...odds];
    newOdds[idx].val = val;
    setOdds(newOdds);
  };

  const calculate = () => {
    const validOdds = odds.map(o => parseFloat(o.val)).filter(v => !isNaN(v) && v > 1);
    if (validOdds.length !== odds.length) return null;

    const impliedProbSum = validOdds.reduce((acc, odd) => acc + (1 / odd), 0);
    const stake = parseFloat(totalStake) || 0;

    const profitPct = (1 / impliedProbSum - 1) * 100;
    const isSurebet = profitPct > 0;

    // Calculate individual stakes
    // Stake_i = (TotalStake / ImpliedSum) / Odd_i
    const results = validOdds.map(odd => {
        const indStake = (stake / impliedProbSum) / odd;
        return {
            stake: indStake,
            odd: odd
        };
    });

    return { profitPct, results, isSurebet, profitAmount: stake * (profitPct / 100) };
  };

  const data = calculate();

  return (
    <div className="max-w-2xl mx-auto w-full animate-in fade-in zoom-in duration-300">
      <h2 className="text-3xl font-bold text-white mb-8 text-center">Calculadora Surebet</h2>

      <div className="bg-slate-800 p-6 rounded-2xl shadow-xl border border-slate-700">

        {/* Toggle 2-way / 3-way */}
        <div className="flex justify-center mb-6">
            <div className="bg-slate-900 p-1 rounded-lg flex">
                <button 
                    onClick={() => setIs3Way(false)}
                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${!is3Way ? 'bg-emerald-500 text-white' : 'text-slate-400 hover:text-white'}`}
                >
                    2 Opções
                </button>
                <button 
                    onClick={() => setIs3Way(true)}
                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${is3Way ? 'bg-emerald-500 text-white' : 'text-slate-400 hover:text-white'}`}
                >
                    3 Opções
                </button>
            </div>
        </div>

        <div className="space-y-4">
             <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">Investimento Total</label>
                <input
                    type="number"
                    value={totalStake}
                    onChange={(e) => setTotalStake(e.target.value)}
                    className="w-full bg-slate-900 border border-slate-600 text-white rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none"
                />
            </div>

            <div className={`grid gap-4 ${is3Way ? 'grid-cols-3' : 'grid-cols-2'}`}>
                {odds.map((o, idx) => (
                    <div key={o.id}>
                        <label className="block text-sm font-medium text-slate-400 mb-1">Odd {idx + 1}</label>
                        <input
                            type="number"
                            value={o.val}
                            onChange={(e) => updateOdd(idx, e.target.value)}
                            className="w-full bg-slate-900 border border-slate-600 text-white rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none"
                            placeholder="Ex: 2.10"
                        />
                    </div>
                ))}
            </div>

            {data && (
                <div className={`mt-6 rounded-xl p-6 border text-center ${data.isSurebet ? 'bg-emerald-900/20 border-emerald-500/50' : 'bg-red-900/20 border-red-500/50'}`}>
                    <h3 className={`text-xl font-bold mb-2 ${data.isSurebet ? 'text-emerald-400' : 'text-red-400'}`}>
                        {data.isSurebet ? 'Oportunidade de Arbitragem!' : 'Sem Arbitragem'}
                    </h3>
                    <p className="text-white text-lg mb-4">
                        Lucro Garantido: <span className="font-bold">{data.profitPct.toFixed(2)}%</span> (R$ {data.profitAmount.toFixed(2)})
                    </p>

                    <div className={`grid gap-4 ${is3Way ? 'grid-cols-3' : 'grid-cols-2'} text-left mt-4 border-t border-slate-700/50 pt-4`}>
                        {data.results.map((res, i) => (
                            <div key={i} className="bg-slate-900/50 p-3 rounded-lg">
                                <p className="text-xs text-slate-500 uppercase">Apostar na Odd {odds[i].val}</p>
                                <p className="font-bold text-white">R$ {res.stake.toFixed(2)}</p>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

